      new Notice(t('notifications.itemRemoved', { item: itemDescription }));
    } catch (error) {
      this.plugin.logger.error('Error removing item:', error);
      new Notice(t('notifications.itemRemoveError', { error: (error as Error).message }));
    }
  }

