  /**
   * Open barcode scanner modal
   */
  private openBarcodeScanner(): void {
    // Fixed: Add null check instead of non-null assertion
    if (!this.plugin) {
      new Notice('Plugin context not available for barcode scanning');
      return;
    }

    const scannerModal = new BarcodeScannerModal(this.app, this.plugin, (barcode: string) =>
      void this.handleBarcodeScanned(barcode)
    );

    scannerModal.open();
  }

  /**
   * Handle barcode scan result
   */
  async handleBarcodeScanned(barcode: string): Promise<void> {
    // Validate barcode
    if (!validateBarcodeChecksum(barcode)) {
      new Notice(t('barcode.manual.checksumWarning', { code: barcode }));
    }

    // Set the barcode in search input
    this.searchInput.value = barcode;
    this.isBarcodeSearch = true;

    // Perform barcode-specific search
    await this.performBarcodeSearch(barcode);

    // Focus back on input for potential manual editing
    window.setTimeout(() => {
      this.searchInput.focus();
      this.searchInput.select();
    }, 100);
  }

  /**
   * Perform barcode-specific search with proper result handling
   */
  private async performBarcodeSearch(barcode: string): Promise<void> {
    if (!this.plugin) {
      new Notice('Plugin context not available for barcode search');
      return;
    }

    this.loadingIndicator.classList.remove('is-hidden');
    this.noResultsMessage.classList.add('is-hidden');
    this.isSearching = true;

    // Clear previous results
    this.resultsContainer.empty();
    this.results = [];
    this.allResults = [];

    try {
      const settings = this.plugin.settings;

      // Configure sources for barcode search
      const sources = {
        openFoodFacts: { enabled: settings.openFoodFactsEnabled !== false },
        usda:
          settings.usdaEnabled && settings.usdaApiKey
            ? { enabled: true, apiKey: settings.usdaApiKey }
            : undefined,
      };

      // Get user's locale
      const userLocale = this.plugin.i18nManager?.getCurrentLocale() || 'en';

      // Search by barcode
      const barcodeResults = await searchByBarcode(this.app, barcode, sources, userLocale);

      // Properly set the results
      this.allResults = barcodeResults;
      this.results = barcodeResults;
      this.hasMoreResults = false; // Barcode search is typically exact match
      this.currentSearchTerm = barcode; // Set current search term

      this.loadingIndicator.classList.add('is-hidden');

      if (barcodeResults.length > 0) {
        // Build Fuse index for barcode results
        const foodDocs: FoodDoc[] = barcodeResults.map(unifiedResultToFoodDoc);
        buildFuseIndex(this.currentTab, foodDocs);

        // Call renderResults with the barcode as search term
        this.renderResults(barcode);
        new Notice(
          t('barcode.scanner.foundResults', { count: barcodeResults.length, code: barcode })
        );
      } else {
        // If no barcode results, show no results message
        this.noResultsMessage.textContent = t('barcode.scanner.noResults', { code: barcode });
        this.noResultsMessage.classList.remove('is-hidden');

        // Clear search input and reset for text search after a delay
        window.setTimeout(() => {
          this.searchInput.value = '';
          this.isBarcodeSearch = false;
          this.searchInput.placeholder = t('food.search.placeholder');
          this.searchInput.focus();
        }, 2000);
      }
    } catch (error) {
      this.plugin.logger.error('Barcode search error:', error);
      this.loadingIndicator.classList.add('is-hidden');
      new Notice(t('barcode.errors.apiError', { error: (error as Error).message }));

      // Reset for manual search
      this.isBarcodeSearch = false;
      this.noResultsMessage.textContent = `Barcode search failed: ${(error as Error).message}`;
      this.noResultsMessage.classList.remove('is-hidden');
    } finally {
      this.isSearching = false;
    }
  }

  private createLoadingIndicator(): void {
    this.loadingIndicator = this.contentEl.createDiv({
      cls: 'loading-indicator macros-loading-indicator is-hidden',
      text: t('food.search.searching'),
    });
  }

  private createResultsContainer(): void {
    this.resultsContainer = this.contentEl.createDiv({
      cls: 'results-container macros-results-container',
    });
  }

  private createNoResultsMessage(): void {
    this.noResultsMessage = this.contentEl.createDiv({
      cls: 'no-results-message is-hidden',
      text: t('food.search.noResults'),
    });
  }

  handleSearchInput = () => {
    const searchTerm = this.searchInput.value.trim();

    // Reset barcode search flag when user starts typing
    if (!this.isBarcodeSearch || searchTerm !== this.currentSearchTerm) {
      this.isBarcodeSearch = false;
    }

    if (this.searchTimeout) {
      window.clearTimeout(this.searchTimeout);
    }

    // Cancel any ongoing search
    if (this.currentSearchAbortController) {
      this.currentSearchAbortController.abort();
      this.currentSearchAbortController = null;
    }

    this.selectedIndex = -1;

    if (!searchTerm) {
      this.resultsContainer.empty();
      this.noResultsMessage.classList.add('is-hidden');
      this.loadingIndicator.classList.add('is-hidden');
      return;
    }

    // Use Fuse search if we have results indexed for current tab
    const fuseResults = fuseSearch(this.currentTab, searchTerm);
    if (fuseResults.length > 0) {
      this.results = fuseResults;
      this.renderResults(searchTerm);
      return;
    }

    this.loadingIndicator.classList.remove('is-hidden');
    this.noResultsMessage.classList.add('is-hidden');

    this.searchTimeout = window.setTimeout(() => {
      const currentSearchTerm = this.searchInput.value.trim();
      if (currentSearchTerm === searchTerm) {
        // Detect if this looks like a barcode (all numbers, 8-14 digits)
        if (/^\d{8,14}$/.test(searchTerm)) {
          this.isBarcodeSearch = true;
          void this.performBarcodeSearch(searchTerm);
        } else {
          void this.performSearch(searchTerm);
        }
      }
    }, 300);
  };

  handleKeyboardNavigation = (event: KeyboardEvent) => {
    if (this.results.length === 0) return;

    if (event.key === 'ArrowDown') {
      event.preventDefault();
      this.selectedIndex = (this.selectedIndex + 1) % this.results.length;
      this.highlightSelectedResult();
      this.scrollToSelectedResult();
    } else if (event.key === 'ArrowUp') {
      event.preventDefault();
      this.selectedIndex = (this.selectedIndex - 1 + this.results.length) % this.results.length;
      this.highlightSelectedResult();
      this.scrollToSelectedResult();
    } else if (event.key === 'Enter' && this.selectedIndex >= 0) {
      event.preventDefault();
      void this.handleFoodSelection(this.results[this.selectedIndex]);
    }
  };

  highlightSelectedResult() {
    this.resultsContainer.querySelectorAll('.food-result-item').forEach((item, index) => {
      if (index === this.selectedIndex) {
        item.addClass('highlighted-result');
      } else {
        item.removeClass('highlighted-result');
      }
    });
  }

  scrollToSelectedResult() {
    const selectedElement = this.resultsContainer.querySelector('.highlighted-result');
    if (selectedElement) {
      selectedElement.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    }
  }

  /**
   * Enhanced search with Fuse.js integration and fallback variants
   */
  async performSearch(searchTerm: string) {
    // Create new abort controller for this search
    this.currentSearchAbortController = new AbortController();
    const searchAbortSignal = this.currentSearchAbortController.signal;

    // Store the search term at the start of the request
    const requestSearchTerm = searchTerm;

    if (this.isSearching) {
      // If already searching, the abort controller above will cancel the previous request
    }

    this.isSearching = true;

    try {
      if (!this.plugin) {
        throw new Error('Plugin context not available');
      }

      // Check if search was aborted before making the request
      if (searchAbortSignal.aborted) {
        return;
      }

      // Validate that search term still matches current input
      const currentInputValue = this.searchInput.value.trim();
      if (currentInputValue !== requestSearchTerm) {
        this.plugin.logger.debug(
          `Search cancelled: input changed from "${requestSearchTerm}" to "${currentInputValue}"`
        );
        return;
      }

      // Fixed: Use proper typing instead of any
      const settings = this.plugin.settings;

      // Reset for new search
      this.currentPage = 0;
      this.hasMoreResults = true;
      this.allResults = [];

      let newResults: UnifiedFoodResult[] = [];

      // Check if search was aborted before processing results
      if (searchAbortSignal.aborted) {
        return;
      }

      // Try primary search first
      newResults = await this.performApiSearch(requestSearchTerm, settings, searchAbortSignal);

      // If no results, try search variants (singular/plural)
      if (newResults.length === 0) {
        const variants = generateSearchVariants(requestSearchTerm);

        for (const variant of variants) {
          if (searchAbortSignal.aborted) return;

          const variantResults = await this.performApiSearch(variant, settings, searchAbortSignal);

          if (variantResults.length > 0) {
            newResults = variantResults;
            break;
          }
        }
      }

      // Final validation before showing results
      const finalInputValue = this.searchInput.value.trim();
      if (finalInputValue !== requestSearchTerm || searchAbortSignal.aborted) {
        this.plugin.logger.debug(
          `Search results discarded: input changed from "${requestSearchTerm}" to "${finalInputValue}" or search was aborted`
        );
        return;
      }

      this.allResults = newResults;
      this.results = newResults;
      this.hasMoreResults = newResults.length > 0;

      // Build Fuse index for the results
      if (newResults.length > 0) {
        const foodDocs: FoodDoc[] = newResults.map(unifiedResultToFoodDoc);
        buildFuseIndex(this.currentTab, foodDocs);
      }

      this.loadingIndicator.classList.add('is-hidden');
      this.renderResults(requestSearchTerm);
      this.storeResultsInCache(requestSearchTerm);

      // Ensure search input maintains focus after results are rendered
      window.setTimeout(() => {
        this.searchInput.focus();
      }, 10);
    } catch (error) {
      // Don't show error if search was aborted
      if (searchAbortSignal.aborted) {
        return;
      }

      if (this.plugin && this.plugin.logger) {
        this.plugin.logger.error('Error fetching food data:', error);
      }
      this.loadingIndicator.classList.add('is-hidden');
      new Notice(t('food.search.error.fetchFailed'));
    } finally {
      this.isSearching = false;
      // Clear the abort controller if this search completed normally
      if (
        this.currentSearchAbortController &&
        this.currentSearchAbortController.signal === searchAbortSignal
      ) {
        this.currentSearchAbortController = null;
      }
    }
  }

  /**
   * Perform the actual API search for a given term
   */
  private async performApiSearch(
    searchTerm: string,
    // Fixed: Use proper typing instead of any
    settings: typeof this.plugin.settings,
    searchAbortSignal: AbortSignal
  ): Promise<UnifiedFoodResult[]> {
    let newResults: UnifiedFoodResult[] = [];

    if (this.currentTab === 'openfoodfacts') {
      // Open Food Facts only search
      if (settings.openFoodFactsEnabled !== false) {
        // Check if this is a barcode search first
        const cleanQuery = searchTerm.replace(/\s+/g, '');
        const isBarcodeSearch = /^\d{8,14}$/.test(cleanQuery);

        if (isBarcodeSearch) {
          // Use the barcode search function directly
          const { searchByBarcode } = await import('../../core/barcodeSearch');

          const sources = {
            openFoodFacts: { enabled: true },
            usda: undefined, // Don't search USDA for barcodes when on OFF tab
          };

          const userLocale = this.plugin?.i18nManager?.getCurrentLocale() || 'en';
          newResults = await searchByBarcode(this.app, cleanQuery, sources, userLocale);
        } else {
          // Regular text search
          // Get user's locale for localization
          const userLocale = this.plugin?.i18nManager?.getCurrentLocale() || 'en';
          const offLanguage =
            settings.openFoodFactsLanguage === 'auto' ? userLocale : settings.openFoodFactsLanguage;

          // Import and use Open Food Facts search
          const { searchOpenFoodFacts } = await import('../../core/openFoodFacts');
          const offResults = await searchOpenFoodFacts(
            this.app,
            searchTerm,
            0,
            this.maxResults,
            offLanguage
          );

          // Convert to UnifiedFoodResult format
          newResults = offResults.map((item) => ({
            id: `off_${item.code}`,
            name: item.productName,
            description: item.displayDescription,
            gramsServing: item.gramsServing,
            source: 'openfoodfacts' as const,
            brandName: item.brands,
            nutritionGrade: item.nutritionGrade,
            novaGroup: item.novaGroup,
            dataQuality: item.dataQuality,
            completeness: item.completeness,
            ecoscore: item.ecoscore,
            imageUrl: item.imageUrl,
            categories: item.categories,
            ingredients: item.ingredientsText,
            micronutrients: item.micronutrients,
            raw: item,
          }));

          // Apply data quality filter
          if (settings.openFoodFactsDataQualityFilter !== 'all') {
            newResults = newResults.filter((result) => {
              if (settings.openFoodFactsDataQualityFilter === 'high') {
                return result.dataQuality === 'high';
              } else if (settings.openFoodFactsDataQualityFilter === 'medium') {
                return result.dataQuality === 'high' || result.dataQuality === 'medium';
              }
              return true;
            });
          }
        }
      }
    } else if (this.currentTab === 'usda-foundation') {
      // Foundation only search
      if (settings.usdaEnabled && settings.usdaApiKey) {
        newResults = await searchFoundationFoodsOnly(
          this.app,
          searchTerm,
          this.maxResults,
          settings.usdaApiKey
        );
      }
    } else if (this.currentTab === 'usda-branded') {
      // Branded only search
      if (settings.usdaEnabled && settings.usdaApiKey) {
        const usdaResults = await searchFoods(
          this.app,
          searchTerm,
          0,
          this.maxResults,
          settings.usdaApiKey
        );
        newResults = usdaResults
          .filter((item) => item.isBranded)
          .map((item) => ({
            id: `usda_${item.fdcId}`,
            name: item.description,
            description: item.displayDescription,
            gramsServing: item.gramsServing,
            source: 'usda' as const,
            brandName: item.brandName,
            isFoundation: item.isFoundation,
            isBranded: item.isBranded,
            isSrLegacy: item.isSrLegacy,
            dataType: item.dataType,
            micronutrients: item.micronutrients,
            raw: item,
          }));
      }
    } else if (this.currentTab === 'usda-legacy') {
      // Legacy only search
      if (settings.usdaEnabled && settings.usdaApiKey) {
        const usdaResults = await searchFoods(
          this.app,
          searchTerm,
          0,
          this.maxResults,
          settings.usdaApiKey
        );
        newResults = usdaResults
          .filter((item) => item.isSrLegacy)
          .map((item) => ({
            id: `usda_${item.fdcId}`,
            name: item.description,
            description: item.displayDescription,
            gramsServing: item.gramsServing,
            source: 'usda' as const,
            brandName: item.brandName,
            isFoundation: item.isFoundation,
            isBranded: item.isBranded,
            isSrLegacy: item.isSrLegacy,
            dataType: item.dataType,
            micronutrients: item.micronutrients,
            raw: item,
          }));
      }
    } else if (this.currentTab === 'fatsecret') {
      // Search ONLY FatSecret, completely exclude Open Food Facts and USDA
      if (settings.fatSecretEnabled && settings.fatSecretApiKey && settings.fatSecretApiSecret) {
        // Import FatSecret search function directly
        const { searchFatSecret } = await import('../../core/search');

        newResults = await searchFatSecret(
          this.app,
          searchTerm,
          this.currentPage,
          this.maxResults,
          settings.fatSecretApiKey,
          settings.fatSecretApiSecret
        );
      }
    } else {
      // Determine which sources to search based on current tab
      const sources: {
        fatSecret?: { enabled: boolean; apiKey: string; apiSecret: string };
        usda?: { enabled: boolean; apiKey: string };
        openFoodFacts?: { enabled: boolean };
      } = {};

      if (this.currentTab === 'all') {
        // Search all available sources
        if (settings.fatSecretEnabled && settings.fatSecretApiKey && settings.fatSecretApiSecret) {
          sources.fatSecret = {
            enabled: true,
            apiKey: settings.fatSecretApiKey,
            apiSecret: settings.fatSecretApiSecret,
          };
        }
        if (settings.usdaEnabled && settings.usdaApiKey) {
          sources.usda = {
            enabled: true,
            apiKey: settings.usdaApiKey,
          };
        }
        if (settings.openFoodFactsEnabled !== false) {
          sources.openFoodFacts = {
            enabled: true,
          };
        }
      }

      // Get user's locale for Open Food Facts
      const userLocale = this.plugin?.i18nManager?.getCurrentLocale() || 'en';
      const offLanguage =
        settings.openFoodFactsLanguage === 'auto' ? userLocale : settings.openFoodFactsLanguage;

      newResults = await searchAllSources(
        this.app,
        searchTerm,
        this.currentPage,
        this.maxResults,
        sources,
        offLanguage
      );

      // Apply Open Food Facts data quality filter if applicable
      if (settings.openFoodFactsDataQualityFilter !== 'all') {
        newResults = newResults
          .map((result) => {
            if (result.source === 'openfoodfacts') {
              if (
                settings.openFoodFactsDataQualityFilter === 'high' &&
                result.dataQuality !== 'high'
              ) {
                return null;
              } else if (
                settings.openFoodFactsDataQualityFilter === 'medium' &&
                result.dataQuality === 'low'
              ) {
                return null;
              }
            }
            return result;
          })
          .filter(Boolean);
      }
    }

    return newResults;
  }

  escapeRegExp(string: string): string {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\');
  }

  /**
   * Render a compact micronutrient summary for a result, when the food carries
   * per-100g micronutrient data. Foods whose source has no recorded
   * micronutrients (e.g. many Open Food Facts entries, or FatSecret results
   * before the food is selected) simply render nothing.
   */
  private renderMicronutrientSummary(container: HTMLElement, food: UnifiedFoodResult) {
    const micros = food.micronutrients;
    if (!micros) return;

    const presentKeys = MICRONUTRIENT_KEYS.filter(
      (key) => micros[key] != null && Number.isFinite(micros[key]) && micros[key] !== 0
    );
    if (presentKeys.length === 0) return;

    const grams = food.gramsServing || 100;
    const microsDiv = container.createDiv({ cls: 'food-result-micros' });
    microsDiv.createSpan({
      cls: 'food-result-micros-label',
      text: t('food.search.micronutrients', { grams: String(grams) }),
    });

    const chipsWrap = microsDiv.createDiv({ cls: 'food-result-micros-chips' });
    for (const key of presentKeys) {
      const def = MICRONUTRIENT_MAP[key];
      const label = def ? def.label : key;
      const unit = def ? def.unit : '';
      chipsWrap.createSpan({
        cls: 'food-result-micro-chip',
        text: `${label} ${formatMicroAmount(micros[key])}${unit}`,
      });
    }
  }

  renderResults(searchTerm: string) {
    this.resultsContainer.empty();

    if (this.results.length === 0) {
      this.noResultsMessage.classList.remove('is-hidden');
      return;
    }

    this.noResultsMessage.classList.add('is-hidden');

    const normalizedQuery = searchTerm.toLowerCase();
    const escapedSearchTerm = this.escapeRegExp(searchTerm);

    // For barcode searches, show all results regardless of name matching
    const resultsToShow = this.isBarcodeSearch
      ? this.results
      : this.results.filter((food) => food.name.toLowerCase().includes(normalizedQuery));

    resultsToShow.forEach((food, index) => {
      const foodDiv = this.resultsContainer.createDiv({
        cls: `food-result-item ${this.isBarcodeSearch ? 'barcode-result' : ''}`,
      });

      // Create main content container
      const contentDiv = foodDiv.createDiv({ cls: 'food-result-content' });

      // Food name with highlighting and brand info
      const nameDiv = contentDiv.createDiv({ cls: 'food-result-name' });
      const nameContentDiv = nameDiv.createDiv({ cls: 'food-name-content' });

      // Only highlight text matches for non-barcode searches
      if (this.isBarcodeSearch) {
        // For barcode searches, just show the name without highlighting
        nameContentDiv.createSpan({ text: food.name });
      } else {
        // For text searches, highlight matching text
        const regex = new RegExp(`(${escapedSearchTerm})`, 'gi');
        const parts = food.name.split(regex);

        parts.forEach((part) => {
          if (part.toLowerCase() === searchTerm.toLowerCase()) {
            nameContentDiv.createEl('strong', { text: part });
          } else if (part) {
            nameContentDiv.createSpan({ text: part });
          }
        });
      }

      // Add brand name if available
      if (food.brandName) {
        nameContentDiv.createSpan({
          cls: 'food-brand-name',
          text: ` (${food.brandName})`,
        });
      }

      // Create enhanced chips container
      const chipsDiv = nameDiv.createDiv({ cls: 'food-result-chips' });

      // Add enhanced source chip with more specific labeling
      let sourceLabel = '';
      let chipClass = `macros-source-chip macros-source-${food.source}`;

      if (food.source === 'usda') {
        if (food.isFoundation) {
          sourceLabel = 'USDA Foundation';
          chipClass += ' macros-source-foundation';
        } else if (food.isSrLegacy) {
          sourceLabel = 'USDA SR Legacy';
          chipClass += ' macros-source-sr-legacy';
        } else if (food.isBranded) {
          sourceLabel = 'USDA Branded';
          chipClass += ' macros-source-branded';
        } else {
          sourceLabel = 'USDA';
        }
      } else if (food.source === 'openfoodfacts') {
        sourceLabel = 'Open Food Facts';
        chipClass += ' macros-source-openfoodfacts';
      } else {
        sourceLabel = t(`food.search.source.${food.source}`);
      }

      chipsDiv.createSpan({
        cls: chipClass,
        text: sourceLabel,
      });

      // Add quality indicators for different sources
      if (food.isFoundation) {
        chipsDiv.createSpan({
          cls: 'macros-quality-chip macros-foundation-indicator',
          text: 'High Quality',
          attr: { title: 'Foundation data is the most reliable and comprehensive USDA data' },
        });
      } else if (food.source === 'openfoodfacts') {
        // Add data quality indicator for Open Food Facts
        if (food.dataQuality === 'high') {
          chipsDiv.createSpan({
            cls: 'macros-quality-chip macros-off-high-quality',
            text: 'High Quality',
            attr: { title: 'High quality Open Food Facts data' },
          });
        } else if (food.dataQuality === 'medium') {
          chipsDiv.createSpan({
            cls: 'macros-quality-chip macros-off-medium-quality',
            text: 'Medium Quality',
            attr: { title: 'Medium quality Open Food Facts data' },
          });
        }

        // Add nutrition grade if available
        if (
          food.nutritionGrade &&
          ['A', 'B', 'C', 'D', 'E'].includes(food.nutritionGrade.toUpperCase())
        ) {
          chipsDiv.createSpan({
            cls: `macros-nutrition-grade macros-nutrition-grade-${food.nutritionGrade.toLowerCase()}`,
            text: `Grade ${food.nutritionGrade.toUpperCase()}`,
            attr: { title: 'Nutri-Score nutrition grade' },
          });
        }

        // Add NOVA group indicator if available
        if (food.novaGroup && food.novaGroup >= 1 && food.novaGroup <= 4) {
          // Fixed: Removed unused variable assignment
          chipsDiv.createSpan({
            cls: `macros-nova-chip macros-nova-${food.novaGroup}`,
            text: `NOVA ${food.novaGroup}`,
            attr: { title: 'NOVA food processing classification' },
          });
        }
      }

      // Food description
      // Fixed: Prefix unused variable with underscore
      contentDiv.createDiv({
        cls: 'food-result-description',
        text: food.description,
      });

      // Micronutrient summary (only for foods whose source provided per-100g
      // micronutrient data; many database entries have none recorded).
      this.renderMicronutrientSummary(contentDiv, food);

      // Add product image for Open Food Facts if available
      if (food.source === 'openfoodfacts' && food.imageUrl) {
        const imageDiv = contentDiv.createDiv({ cls: 'food-result-image' });
        const img = imageDiv.createEl('img', {
          attr: {
            src: food.imageUrl,
            alt: food.name,
            loading: 'lazy',
          },
          cls: 'food-product-image',
        });

        // Handle image load errors gracefully
        img.addEventListener('error', () => {
          imageDiv.addClass('macros-u-hidden');
        });
      }

      if (index === this.selectedIndex) {
        foodDiv.addClass('highlighted-result');
      }

      this.component.registerDomEvent(foodDiv, 'click', () => {
        void this.handleFoodSelection(food);
      });

      this.component.registerDomEvent(foodDiv, 'mouseenter', () => {
        this.selectedIndex = index;
        this.highlightSelectedResult();
      });
    });

    // Add infinite scroll functionality
    this.setupInfiniteScroll(searchTerm);
  }

  private async handleFoodSelection(food: UnifiedFoodResult): Promise<void> {
    // Check if this is from API search (not already saved food)
    if (food.source === 'usda' || food.source === 'fatsecret' || food.source === 'openfoodfacts') {
      await this.promptForFileName(food);
    } else {
      // Directly call onSelect for already saved foods
      this.onSelect(food);
      this.close();
    }
  }

  private async promptForFileName(food: UnifiedFoodResult): Promise<void> {
    // Create a simple modal for file name input
    const modal = new FileNameModal(
      this.app,
      food.name,
      food.gramsServing || 100, // Pass the original serving size
      async (fileName: string, defaultServing?: number) => {
        // Use the SAME sanitization logic as DataManager
        const safeFileName = this.sanitizeFileName(fileName);

        // Check if sanitization changed the filename significantly
        if (safeFileName !== fileName.trim()) {
          this.plugin?.logger.debug(`Filename sanitized: "${fileName}" -> "${safeFileName}"`);
        }

        // Check existence using the sanitized filename
        const existsResult = await this.checkFileExists(safeFileName);
        if (existsResult.exists) {
          new Notice(
            `A food item with the name "${safeFileName}" already exists in your Nutrition folder. Please choose a different name to avoid conflicts.`
          );
          return false; // Keep modal open
        }

        // File name is unique, proceed with saving
        try {
          // Pass the ORIGINAL filename and default serving to saveFoodFile
          await this.saveFoodFile(food, fileName, defaultServing);
          // Don't call this.onSelect(food) here - saveFoodFile already shows success notice
          this.close();
          return true; // Close modal
        } catch (error) {
          this.plugin?.logger.error('Error saving food file:', error);
          new Notice(`Error saving food item: ${(error as Error).message}`);
          return false; // Keep modal open
        }
      },
      this.plugin
    );

    modal.open();
  }

  // Proper file existence check with normalization
  private async checkFileExists(fileName: string): Promise<{ exists: boolean; path?: string }> {
    if (!this.plugin) return { exists: false };

    try {
      // Use the SAME sanitization logic as DataManager
      const safeFileName = this.sanitizeFileName(fileName);

      const folder = normalizePath(this.plugin.settings.storageFolder);
      const filePath = normalizePath(`${folder}/${safeFileName}.md`);

      // Use proper Obsidian API to check file existence
      const existingFile = this.app.vault.getAbstractFileByPath(filePath);

      // Ensure it's actually a file, not a folder
      const exists = existingFile instanceof TFile;

      this.plugin.logger.debug(`File existence check: ${safeFileName}.md -> ${exists}`);

      return { exists, path: filePath };
    } catch (error) {
      this.plugin.logger.error('Error checking file existence:', error);
      return { exists: false };
    }
  }

  // Helper to sanitize filename - MUST match DataManager.createSafeFileName()
  private sanitizeFileName(fileName: string): string {
    return fileName
      .replace(/[<>:"/\\|?*]/g, '') // Remove invalid filename characters
      .replace(/\s+/g, ' ') // Normalize spaces
      .replace(/^\s+|\s+$/g, '') // Trim whitespace
      .substring(0, 100) // Limit length
      .replace(/\.$/, ''); // Remove trailing period if present
  }

  private async saveFoodFile(
    food: UnifiedFoodResult,
    fileName: string,
    defaultServing?: number
  ): Promise<void> {
    if (!this.plugin) return;

    // Extract nutrition data from the food result
    let calories = 0;
    let protein = 0;
    let fat = 0;
    let carbs = 0;
    let fiber = 0;
    let sugars = 0;
    let salt = 0;

    // For Open Food Facts, we have direct access to nutrition data
    // Fixed: Use proper typing instead of any
    if (food.source === 'openfoodfacts' && food.raw && typeof food.raw === 'object') {
      const offData = food.raw as Record<string, unknown>;
      calories = (offData.calories as number) || 0;
      protein = (offData.protein as number) || 0;
      fat = (offData.fat as number) || 0;
      carbs = (offData.carbs as number) || 0;
      fiber = (offData.fiber as number) || 0;
      sugars = (offData.sugars as number) || 0;
      salt = (offData.salt as number) || 0;
    } else {
      // Parse nutrition data from description for other sources
      if (food.description) {
        const caloriesMatch = food.description.match(/Calories:\s*(\d+(?:\.\d+)?)/i);
        const proteinMatch = food.description.match(/Protein:\s*(\d+(?:\.\d+)?)g/i);
        const fatMatch = food.description.match(/Fat:\s*(\d+(?:\.\d+)?)g/i);
        const carbsMatch = food.description.match(/Carbs:\s*(\d+(?:\.\d+)?)g/i);

        calories = caloriesMatch ? parseFloat(caloriesMatch[1]) : 0;
        protein = proteinMatch ? parseFloat(proteinMatch[1]) : 0;
        fat = fatMatch ? parseFloat(fatMatch[1]) : 0;
        carbs = carbsMatch ? parseFloat(carbsMatch[1]) : 0;
      }
    }

    const servingSize = food.gramsServing || 100;

    // Resolve micronutrients for this food. USDA and Open Food Facts attach
    // canonical per-100g data to the search result; FatSecret only exposes it
    // via a detail lookup, so fetch it on demand here.
    let micronutrients: Record<string, number> = {};
    if (food.micronutrients && typeof food.micronutrients === 'object') {
      micronutrients = { ...food.micronutrients };
    }
    if (
      Object.keys(micronutrients).length === 0 &&
      food.source === 'fatsecret' &&
      food.raw &&
      typeof food.raw === 'object'
    ) {
      const foodId = (food.raw as Record<string, unknown>).food_id;
      const fsKey = this.plugin.settings.fatSecretApiKey?.trim();
      const fsSecret = this.plugin.settings.fatSecretApiSecret?.trim();
      if (foodId && fsKey && fsSecret) {
        try {
          const fsMicros = await fetchFatSecretMicronutrients(
            this.app,
            String(foodId),
            fsKey,
            fsSecret
          );
          if (fsMicros) micronutrients = fsMicros.micronutrients;
        } catch (microErr) {
          this.plugin.logger.error('Error fetching FatSecret micronutrients:', microErr);
        }
      }
    }
    // Source values are per 100g; rescale to the stored serving size so they
    // match the macros and the scaling done by extractMicronutrients().
    if (Object.keys(micronutrients).length > 0 && servingSize !== 100) {
      const microScale = servingSize / 100;
      const rescaled: Record<string, number> = {};
      for (const [k, v] of Object.entries(micronutrients)) rescaled[k] = v * microScale;
      micronutrients = rescaled;
    }

    // Create the markdown content
    const fdcId =
      food.source === 'usda' && food.raw && typeof food.raw === 'object' && 'fdcId' in food.raw
        ? String((food.raw as Record<string, unknown>).fdcId)
        : '';

    // Sanitize filename for actual file creation
    const safeFileName = this.sanitizeFileName(fileName);

    let frontmatter = `---
calories: ${calories}
protein: ${protein}
fat: ${fat}
carbs: ${carbs}
serving_size: ${servingSize}g${defaultServing ? `\ndefault_serving_size: ${defaultServing}g` : ''}
source: ${food.source}`;

    // Add source-specific metadata
    if (food.source === 'usda') {
      frontmatter += `\nfdc_id: ${fdcId}\ndata_type: ${food.dataType || ''}`;
    } else if (food.source === 'openfoodfacts') {
      const offCode =
        food.raw && typeof food.raw === 'object' && 'code' in food.raw
          ? String((food.raw as Record<string, unknown>).code)
          : '';
      frontmatter += `\noff_code: ${offCode}`;

      if (fiber) frontmatter += `\nfiber: ${fiber}`;
      if (sugars) frontmatter += `\nsugars: ${sugars}`;
      if (salt) frontmatter += `\nsalt: ${salt}`;
    }

    if (food.brandName) frontmatter += `\nbrand: ${food.brandName}`;
    if (food.nutritionGrade) frontmatter += `\nnutrition_grade: ${food.nutritionGrade}`;
    if (food.novaGroup) frontmatter += `\nnova_group: ${food.novaGroup}`;
    if (food.dataQuality) frontmatter += `\ndata_quality: ${food.dataQuality}`;

    // Add micronutrient keys (read back by extractMicronutrients()).
    for (const microKey of MICRONUTRIENT_KEYS) {
      const microValue = micronutrients[microKey];
      if (microValue == null || !Number.isFinite(microValue) || microValue === 0) continue;
      frontmatter += `\n${microKey}: ${formatMicroAmount(microValue)}`;
    }

    frontmatter += `\ncreated: ${new Date().toISOString()}
---

# ${fileName}

${food.description}

## Nutritional Information (per ${servingSize}g)
- **Calories:** ${calories} kcal
- **Protein:** ${protein}g
- **Fat:** ${fat}g
- **Carbohydrates:** ${carbs}g`;

    if (fiber) frontmatter += `\n- **Fiber:** ${fiber}g`;
    if (sugars) frontmatter += `\n- **Sugars:** ${sugars}g`;
    if (salt) frontmatter += `\n- **Salt:** ${salt}g`;

    // Readable micronutrient breakdown for any nutrients that were resolved.
    const microKeysPresent = MICRONUTRIENT_KEYS.filter(
      (k) =>
        micronutrients[k] != null && Number.isFinite(micronutrients[k]) && micronutrients[k] !== 0
    );
    if (microKeysPresent.length > 0) {
      frontmatter += `\n\n## Micronutrients (per ${servingSize}g)`;
      for (const microKey of microKeysPresent) {
        const def = MICRONUTRIENT_MAP[microKey];
        const microLabel = def ? def.label : microKey;
        const microUnit = def ? def.unit : '';
        frontmatter += `\n- **${microLabel}:** ${formatMicroAmount(micronutrients[microKey])}${microUnit}`;
      }
    }

    let sourceText = '';
    if (food.source === 'usda') {
      sourceText = 'USDA FoodData Central';
    } else if (food.source === 'openfoodfacts') {
      sourceText = 'Open Food Facts (Community Database)';
    } else {
      sourceText = 'FatSecret';
    }

    frontmatter += `\n\n**Source:** ${sourceText}`;
    if (food.brandName) frontmatter += `\n**Brand:** ${food.brandName}`;
    if (food.nutritionGrade)
      frontmatter += `\n**Nutrition Grade:** ${food.nutritionGrade.toUpperCase()} (Nutri-Score)`;
    if (food.novaGroup) {
      const novaLabels = [
        '',
        'Unprocessed or minimally processed',
        'Processed culinary ingredients',
        'Processed foods',
        'Ultra-processed foods',
      ];
      frontmatter += `\n**Processing Level:** NOVA ${food.novaGroup} (${novaLabels[food.novaGroup]})`;
    }
    if (defaultServing && defaultServing !== servingSize) {
      frontmatter += `\n**Default Serving Size:** ${defaultServing}g`;
    }
    if (food.categories) frontmatter += `\n**Categories:** ${food.categories}`;
    if (food.ingredients) frontmatter += `\n\n**Ingredients:** ${food.ingredients}`;

    // Add data quality notice for Open Food Facts
    if (food.source === 'openfoodfacts' && food.dataQuality !== 'high') {
      frontmatter += `\n\n> **Note:** This data comes from the Open Food Facts community database. Please verify nutrition information if accuracy is critical for your needs.`;
    }

    const folderPath = normalizePath(this.plugin.settings.storageFolder);

    // Ensure folder exists
    const folder = this.app.vault.getFolderByPath(folderPath);
    if (!folder) {
      await this.app.vault.createFolder(folderPath);
    }

    const filePath = normalizePath(`${folderPath}/${safeFileName}.md`);

    try {
      // Use proper Obsidian API for file creation
      await this.app.vault.create(filePath, frontmatter);

      let successMessage = `Food item "${fileName}" saved successfully!`;
      if (defaultServing && defaultServing !== servingSize) {
        successMessage += ` Default serving: ${defaultServing}g`;
      }
      new Notice(successMessage);

      // Update the food object with the saved file name
      food.name = fileName;

      // Invalidate cache to make new file immediately available
      this.plugin.dataManager.invalidateFileCache();
    } catch (error) {
      if ((error as Error).message?.includes('already exists')) {
        throw new Error('File already exists. Please choose a different name.');
      }
      throw error;
    }
  }

  private setupInfiniteScroll(searchTerm: string): void {
    // Store current search term
    this.currentSearchTerm = searchTerm;

    // Remove existing scroll listener if it exists
    if (this.scrollHandler) {
      this.resultsContainer.removeEventListener('scroll', this.scrollHandler);
    }

    // Create new scroll handler
    // Fixed: Prefix unused parameter with underscore
    this.scrollHandler = (_event: Event) => {
      void this.handleScroll();
    };

    // Add new scroll listener
    this.component.registerDomEvent(this.resultsContainer, 'scroll', this.scrollHandler);
  }

  private handleScroll = async () => {
    if (this.isLoadingMore || !this.hasMoreResults || this.isBarcodeSearch) return;

    const container = this.resultsContainer;
    const scrollTop = container.scrollTop;
    const scrollHeight = container.scrollHeight;
    const clientHeight = container.clientHeight;

    // Load more when user scrolls to within 100px of bottom
    if (scrollTop + clientHeight >= scrollHeight - 100) {
      await this.loadMoreResults(this.currentSearchTerm);
    }
  };

  private async loadMoreResults(searchTerm: string): Promise<void> {
    if (this.isLoadingMore || !this.hasMoreResults || !this.plugin || this.isBarcodeSearch) return;

    this.isLoadingMore = true;
    this.currentPage++;

    try {
      const settings = this.plugin.settings;
      let newResults: UnifiedFoodResult[] = [];

      if (this.currentTab === 'openfoodfacts') {
        // Load more Open Food Facts results
        if (settings.openFoodFactsEnabled !== false) {
          const userLocale = this.plugin.i18nManager?.getCurrentLocale() || 'en';
          const offLanguage =
            settings.openFoodFactsLanguage === 'auto' ? userLocale : settings.openFoodFactsLanguage;

          const { searchOpenFoodFacts } = await import('../../core/openFoodFacts');
          const offResults = await searchOpenFoodFacts(
            this.app,
            searchTerm,
            this.currentPage,
            this.maxResults,
            offLanguage
          );

          newResults = offResults.map((item) => ({
            id: `off_${item.code}`,
            name: item.productName,
            description: item.displayDescription,
            gramsServing: item.gramsServing,
            source: 'openfoodfacts' as const,
            brandName: item.brands,
            nutritionGrade: item.nutritionGrade,
            novaGroup: item.novaGroup,
            dataQuality: item.dataQuality,
            completeness: item.completeness,
            ecoscore: item.ecoscore,
            imageUrl: item.imageUrl,
            categories: item.categories,
            ingredients: item.ingredientsText,
            micronutrients: item.micronutrients,
            raw: item,
          }));
        }
      } else if (this.currentTab === 'usda-foundation') {
        // Foundation foods don't typically support pagination well, disable
        this.hasMoreResults = false;
        return;
      } else if (this.currentTab === 'usda-branded') {
        // Load more branded results
        if (settings.usdaEnabled && settings.usdaApiKey) {
          const usdaResults = await searchFoods(
            this.app,
            searchTerm,
            this.currentPage,
            this.maxResults,
            settings.usdaApiKey
          );
          newResults = usdaResults
            .filter((item) => item.isBranded)
            .map((item) => ({
              id: `usda_${item.fdcId}`,
              name: item.description,
              description: item.displayDescription,
              gramsServing: item.gramsServing,
              source: 'usda' as const,
              brandName: item.brandName,
              isFoundation: item.isFoundation,
              isBranded: item.isBranded,
              isSrLegacy: item.isSrLegacy,
              dataType: item.dataType,
              micronutrients: item.micronutrients,
              raw: item,
            }));
        }
      } else if (this.currentTab === 'usda-legacy') {
        // Load more legacy results
        if (settings.usdaEnabled && settings.usdaApiKey) {
          const usdaResults = await searchFoods(
            this.app,
            searchTerm,
            this.currentPage,
            this.maxResults,
            settings.usdaApiKey
          );
          newResults = usdaResults
            .filter((item) => item.isSrLegacy)
            .map((item) => ({
              id: `usda_${item.fdcId}`,
              name: item.description,
              description: item.displayDescription,
              gramsServing: item.gramsServing,
              source: 'usda' as const,
              brandName: item.brandName,
              isFoundation: item.isFoundation,
              isBranded: item.isBranded,
              isSrLegacy: item.isSrLegacy,
              dataType: item.dataType,
              micronutrients: item.micronutrients,
              raw: item,
            }));
        }
      } else if (this.currentTab === 'fatsecret') {
        // Load more FatSecret results ONLY
        if (settings.fatSecretEnabled && settings.fatSecretApiKey && settings.fatSecretApiSecret) {
          // Import FatSecret search function directly
          const { searchFatSecret } = await import('../../core/search');

          newResults = await searchFatSecret(
            this.app,
            searchTerm,
            this.currentPage,
            this.maxResults,
            settings.fatSecretApiKey,
            settings.fatSecretApiSecret
          );
        }
      } else if (this.currentTab === 'all') {
        // Load more from all sources
        const sources: {
          fatSecret?: { enabled: boolean; apiKey: string; apiSecret: string };
          usda?: { enabled: boolean; apiKey: string };
          openFoodFacts?: { enabled: boolean };
        } = {};

        if (settings.fatSecretEnabled && settings.fatSecretApiKey && settings.fatSecretApiSecret) {
          sources.fatSecret = {
            enabled: true,
            apiKey: settings.fatSecretApiKey,
            apiSecret: settings.fatSecretApiSecret,
          };
        }
        if (settings.usdaEnabled && settings.usdaApiKey) {
          sources.usda = {
            enabled: true,
            apiKey: settings.usdaApiKey,
          };
        }
        if (settings.openFoodFactsEnabled !== false) {
          sources.openFoodFacts = {
            enabled: true,
          };
        }

        const userLocale = this.plugin.i18nManager?.getCurrentLocale() || 'en';
        const offLanguage =
          settings.openFoodFactsLanguage === 'auto' ? userLocale : settings.openFoodFactsLanguage;

        newResults = await searchAllSources(
          this.app,
          searchTerm,
          this.currentPage,
          this.maxResults,
          sources,
          offLanguage
        );
      }

      if (newResults.length > 0) {
        // Filter out duplicates based on ID
        const existingIds = new Set(this.allResults.map((r) => r.id));
        const uniqueNewResults = newResults.filter((r) => !existingIds.has(r.id));

        if (uniqueNewResults.length > 0) {
          this.allResults.push(...uniqueNewResults);
          this.results = this.allResults;
          this.hasMoreResults = newResults.length > 0;

          // Update Fuse index with new results
          const allFoodDocs: FoodDoc[] = this.allResults.map(unifiedResultToFoodDoc);
          buildFuseIndex(this.currentTab, allFoodDocs);

          // Re-render with new results
          this.renderResults(searchTerm);
          this.storeResultsInCache(searchTerm);
        } else {
          // No new unique results, stop pagination
          this.hasMoreResults = false;
        }
      } else {
        this.hasMoreResults = false;
      }
    } catch {
      this.hasMoreResults = false;
    } finally {
      this.isLoadingMore = false;
    }
  }
}

// Enhanced FileNameModal with default serving size option
class FileNameModal extends Modal {
  private fileNameInput: HTMLInputElement;
  private defaultServingInput: HTMLInputElement;
  private submitButton: HTMLElement;
  private component: Component;
  private isSubmitting = false;

  constructor(
    app: App,
    private defaultName: string,
    private originalServingSize: number, // The serving size from the API result
    private onSubmit: (fileName: string, defaultServing?: number) => Promise<boolean>, // Updated signature
    private plugin?: MacrosPlugin
  ) {
    super(app);
    this.component = new Component();
  }

  onOpen() {
    const { contentEl } = this;
    contentEl.addClass('file-name-modal');

    // Fixed: Prefix unused variables with underscore
    contentEl.createEl('h2', {
      text: 'Save food item',
      cls: 'modal-title',
    });

    contentEl.createEl('p', {
      text: 'Please enter a name and default serving size for this food item:',
      cls: 'modal-description',
    });

    // Input container
    const inputContainer = contentEl.createDiv({ cls: 'modal-content' });

    // File name input section
    const nameSection = inputContainer.createDiv({ cls: 'setting-item' });
    const nameInfo = nameSection.createDiv({ cls: 'setting-item-info' });
    nameInfo.createDiv({
      text: 'File Name:',
      cls: 'setting-item-name',
    });

    const nameControl = nameSection.createDiv({ cls: 'setting-item-control' });
    this.fileNameInput = nameControl.createEl('input', {
      type: 'text',
      cls: 'mod-text',
      value: this.defaultName,
    });

    // Default serving size input section
    const servingSection = inputContainer.createDiv({ cls: 'setting-item' });
    const servingInfo = servingSection.createDiv({ cls: 'setting-item-info' });
    servingInfo.createDiv({
      text: 'Default Serving Size (grams):',
      cls: 'setting-item-name',
    });
    servingInfo.createDiv({
      text: `Optional: Set a custom default serving size for when you add this food to your macros. If not set, it will use ${this.originalServingSize}g from the API.`,
      cls: 'setting-item-description',
    });

    const servingControl = servingSection.createDiv({ cls: 'setting-item-control' });
    this.defaultServingInput = servingControl.createEl('input', {
      type: 'number',
      cls: 'mod-text',
      value: this.originalServingSize.toString(),
      attr: {
        min: '1',
        step: '0.1',
        placeholder: this.originalServingSize.toString(),
      },
    });

    // Button container
    const buttonContainer = contentEl.createDiv({ cls: 'modal-button-container' });

    const cancelButton = buttonContainer.createEl('button', {
      text: 'Cancel',
      cls: 'mod-button',
    });

    this.submitButton = buttonContainer.createEl('button', {
      text: 'Save',
      cls: 'mod-button mod-cta',
    });

    // Event handlers
    this.component.registerDomEvent(cancelButton, 'click', () => {
      this.close();
    });

    this.component.registerDomEvent(this.submitButton, 'click', async () => {
      await this.handleSubmit();
    });

    this.component.registerDomEvent(this.fileNameInput, 'keydown', async (event: KeyboardEvent) => {
      if (event.key === 'Enter') {
        event.preventDefault();
        // Move to serving size input
        this.defaultServingInput.focus();
      } else if (event.key === 'Escape') {
        this.close();
      }
    });

    this.component.registerDomEvent(
      this.defaultServingInput,
      'keydown',
      async (event: KeyboardEvent) => {
        if (event.key === 'Enter') {
          event.preventDefault();
          await this.handleSubmit();
        } else if (event.key === 'Escape') {
          this.close();
        }
      }
    );

    // Auto-focus and select text
    window.setTimeout(() => {
      this.fileNameInput.focus();
      this.fileNameInput.select();
    }, 50);
  }

  private async handleSubmit(): Promise<void> {
    // Prevent double submission
    if (this.isSubmitting) return;

    const fileName = this.fileNameInput.value.trim();
    const defaultServingStr = this.defaultServingInput.value.trim();

    if (!fileName) {
      new Notice('Please enter a file name.');
      this.fileNameInput.focus();
      return;
    }

    // Validate serving size
    const defaultServing = parseFloat(defaultServingStr);
    if (isNaN(defaultServing) || defaultServing <= 0) {
      new Notice('Please enter a valid serving size greater than 0.');
      this.defaultServingInput.focus();
      return;
    }

    // Disable button during submission
    this.isSubmitting = true;
    (this.submitButton as HTMLButtonElement).disabled = true;
    this.submitButton.textContent = 'Saving...';

    try {
      // Pass both filename and default serving size
      const shouldClose = await this.onSubmit(fileName, defaultServing);
      if (shouldClose) {
        this.close();
      }
    } catch (error) {
      new Notice(`Error: ${(error as Error).message}`);
    } finally {
      // Re-enable button
      this.isSubmitting = false;
      (this.submitButton as HTMLButtonElement).disabled = false;
      this.submitButton.textContent = 'Save';
    }
  }

  onClose() {
    this.component.unload();
    this.contentEl.empty();
  }
}

import { Component, Modal, App, Notice } from 'obsidian';
import MacrosPlugin from '../main';
import {
  ZXingLoader,
  BarcodeUtils,
  MobilePermissionHandler,
  CameraDiagnostics,
} from './BarcodeUtils';

export interface BarcodeResult {
  code: string;
  format: string;
  confidence?: number;
}

// Enhanced ZXing interfaces to include BarcodeFormat
interface ZXingBarcodeFormat {
  EAN_13: unknown;
  EAN_8: unknown;
  UPC_A: unknown;
  UPC_E: unknown;
  CODE_128: unknown;
  CODE_39: unknown;
  CODE_93: unknown;
  ITF: unknown;
  CODABAR: unknown;
}

interface EnhancedZXingLibrary {
  BarcodeFormat?: ZXingBarcodeFormat;
  default?: EnhancedZXingLibrary;
}

interface ZXingCodeReader {
  decode?(target: unknown): Promise<ZXingResult>;
  decodeFromCanvas?(canvas: HTMLCanvasElement): Promise<ZXingResult>;
  decodeFromImageData?(imageData: ImageData): Promise<ZXingResult>;
  decodeFromImageElement?(img: HTMLImageElement): Promise<ZXingResult>;
  decodeFromImage?(img: HTMLImageElement): Promise<ZXingResult>;
  decodeFromVideoDevice?(
    deviceId: string | undefined,
    videoElement: HTMLVideoElement
  ): Promise<ZXingResult>;
  decodeBitmap?(imageData: ImageData): Promise<ZXingResult>;
  setHints?(hints: Map<string, unknown>): void;
}

interface ZXingResult {
  getText(): string;
  getBarcodeFormat(): { toString(): string };
  text?: string;
  code?: string;
  format?: string;
}

export class BarcodeScanner extends Component {
  public video: HTMLVideoElement | null = null;
  public canvas: HTMLCanvasElement | null = null;
  public context: CanvasRenderingContext2D | null = null;
  public codeReader: ZXingCodeReader | null = null;
  private stream: MediaStream | null = null;
  private scanning = false;
  private scanInterval: number | null = null;

  constructor(
    private app: App,
    private plugin: MacrosPlugin,
    private onBarcodeDetected: (result: BarcodeResult) => void,
    private onError: (error: string) => void
  ) {
    super();
  }

  async initializeCamera(): Promise<boolean> {
    try {
      this.plugin.logger.debug('Requesting camera permission...');

      const permissionResult = await MobilePermissionHandler.requestCameraPermission();

      if (!permissionResult.granted) {
        const instructions = MobilePermissionHandler.getPermissionInstructions();
        const errorMsg = `${permissionResult.error}\n\n${instructions}`;
        this.onError(errorMsg);
        return false;
      }

      if (!permissionResult.stream) {
        this.onError('Camera stream not available');
        return false;
      }

      this.stream = permissionResult.stream;
      this.plugin.logger.debug('Camera permission granted successfully');
      return true;
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : 'Unknown error';
      this.plugin.logger.error('Camera initialization failed:', error);
      this.onError(`Unexpected camera error: ${errorMessage}`);
      return false;
    }
  }

  async startScanning(videoElement: HTMLVideoElement): Promise<void> {
    if (!this.stream) {
      throw new Error('Camera not initialized');
    }

    this.video = videoElement;
    this.video.srcObject = this.stream;

    await new Promise<void>((resolve, reject) => {
      if (!this.video) {
        reject(new Error('Video element not available'));
        return;
      }

      this.video.addEventListener('loadedmetadata', () => resolve());
      this.video.addEventListener('error', reject);
      this.video.play().catch(reject);
    });

    await this.initializeDecoder();
    this.scanning = true;
    this.startScanLoop();
  }

  private async initializeDecoder(): Promise<void> {
    try {
      this.plugin.logger.debug('Initializing ZXing decoder...');
      this.codeReader = await ZXingLoader.createCodeReader();

      // Configure the reader for better barcode detection
      if (this.codeReader.setHints) {
        const ZXing = (await ZXingLoader.loadZXing()) as EnhancedZXingLibrary;
        const hints = new Map<string, unknown>();

        // Try to enable all barcode formats
        const BarcodeFormat = ZXing.BarcodeFormat || (ZXing.default && ZXing.default.BarcodeFormat);

        if (BarcodeFormat) {
          hints.set('POSSIBLE_FORMATS', [
            BarcodeFormat.EAN_13,
            BarcodeFormat.EAN_8,
            BarcodeFormat.UPC_A,
            BarcodeFormat.UPC_E,
            BarcodeFormat.CODE_128,
            BarcodeFormat.CODE_39,
            BarcodeFormat.CODE_93,
            BarcodeFormat.ITF,
            BarcodeFormat.CODABAR,
          ]);
        }

        hints.set('TRY_HARDER', true);
        hints.set('ALSO_INVERTED', true);

        this.codeReader.setHints(hints);
      }

      this.plugin.logger.debug('ZXing decoder initialized successfully');
    } catch (error) {
      this.plugin.logger.error('Failed to load ZXing library:', error);
      throw new Error(
        'Barcode decoder library failed to load. Please check your internet connection and try again.'
      );
    }
  }

  private startScanLoop(): void {
    if (!this.video || !this.codeReader) return;

    if (!this.canvas) {
      this.canvas = activeDocument.createElement('canvas');
      this.context = this.canvas.getContext('2d', { willReadFrequently: true });
    }

    this.plugin.logger.debug('Starting barcode scan loop');
    let scanAttempts = 0;

    this.scanInterval = window.setInterval(async () => {
      if (!this.scanning || !this.video || !this.canvas || !this.context) {
        return;
      }

      scanAttempts++;
      if (scanAttempts % 10 === 0) {
        this.plugin.logger.debug('Scan attempt', {
          attempt: scanAttempts,
          videoWidth: this.video.videoWidth,
          videoHeight: this.video.videoHeight,
        });
      }

      try {
        // Check if video is ready
        if (this.video.videoWidth === 0 || this.video.videoHeight === 0) {
          if (scanAttempts % 20 === 0) {
            this.plugin.logger.debug('Video not ready yet, waiting...');
          }
          return;
        }

        // Ensure canvas has proper dimensions
        const width = this.video.videoWidth;
        const height = this.video.videoHeight;

        if (width === 0 || height === 0) {
          if (scanAttempts % 20 === 0) {
            this.plugin.logger.debug('Invalid video dimensions, skipping...');
          }
          return;
        }

        this.canvas.width = width;
        this.canvas.height = height;
        this.context.drawImage(this.video, 0, 0, width, height);

        // Try different ZXing API methods
        let result: ZXingResult | null = null;

        try {
          // Method 1: Try decodeFromCanvas (most common for browsers)
          if (this.codeReader && this.codeReader.decodeFromCanvas) {
            result = await this.codeReader.decodeFromCanvas(this.canvas);
          }
          // Method 2: Try decode with canvas (alternative syntax)
          else if (this.codeReader && this.codeReader.decode) {
            result = await this.codeReader.decode(this.canvas);
          }
          // Method 3: Try decodeFromImageData (newer versions)
          else if (this.codeReader && this.codeReader.decodeFromImageData) {
            const imageData = this.context.getImageData(0, 0, width, height);
            result = await this.codeReader.decodeFromImageData(imageData);
          }
          // Method 4: Try decodeBitmap (if that's what we have)
          else if (this.codeReader && this.codeReader.decodeBitmap) {
            const imageData = this.context.getImageData(0, 0, width, height);
            result = await this.codeReader.decodeBitmap(imageData);
          }
          // Method 5: Try decodeFromVideoDevice (for live video)
          else if (this.codeReader && this.codeReader.decodeFromVideoDevice) {
            result = await this.codeReader.decodeFromVideoDevice(undefined, this.video);
          } else {
            if (scanAttempts === 1) {
              this.plugin.logger.error('No suitable decode method found on codeReader');
            }
            return;
          }
        } catch (decodeError: unknown) {
          const error = decodeError as { name?: string; message?: string };
          if (error.name !== 'NotFoundException') {
            if (scanAttempts % 50 === 0) {
              this.plugin.logger.debug('Decode method error', {
                name: error.name,
                message: error.message,
              });
            }
          }
          return;
        }

        if (result) {
          this.plugin.logger.debug('Barcode detected', {
            code: result.getText ? result.getText() : result.text,
            format: result.getBarcodeFormat ? result.getBarcodeFormat() : result.format,
          });

          const barcodeResult: BarcodeResult = {
            code: result.getText ? result.getText() : result.text || result.code || '',
            format: result.getBarcodeFormat
              ? result.getBarcodeFormat().toString()
              : result.format || 'Unknown',
          };

          this.stopScanning();
          this.onBarcodeDetected(barcodeResult);
        }

        // Debug: Check if we're getting valid image data
        if (scanAttempts % 30 === 0) {
          const imageData = this.context.getImageData(0, 0, width, height);
          const avgBrightness = this.calculateAverageBrightness(imageData);
          this.plugin.logger.debug('Image data check', {
            width: imageData.width,
            height: imageData.height,
            avgBrightness: avgBrightness.toFixed(1),
          });
        }
      } catch (error: unknown) {
        const err = error as { name?: string; message?: string };
        if (err.name !== 'NotFoundException') {
          if (scanAttempts % 50 === 0) {
            this.plugin.logger.debug('Scan frame error', {
              name: err.name,
              message: err.message,
            });
          }
        }
        // NotFoundException is normal when no barcode is detected
      }
    }, 300);
  }

  private calculateAverageBrightness(imageData: ImageData): number {
    const data = imageData.data;
    let totalBrightness = 0;
    const pixelCount = data.length / 4;

    for (let i = 0; i < data.length; i += 4) {
      const r = data[i];
      const g = data[i + 1];
      const b = data[i + 2];
      const brightness = 0.299 * r + 0.587 * g + 0.114 * b;
      totalBrightness += brightness;
    }

    return totalBrightness / pixelCount;
  }

  stopScanning(): void {
    this.scanning = false;

    if (this.scanInterval) {
      window.clearInterval(this.scanInterval);
      this.scanInterval = null;
    }

    if (this.stream) {
      this.stream.getTracks().forEach((track) => track.stop());
      this.stream = null;
    }

    if (this.video) {
      this.video.srcObject = null;
      this.video = null;
    }
  }

  async scanImageFile(file: File): Promise<BarcodeResult | null> {
    try {
      this.plugin.logger.debug('Starting image scan', {
        fileName: file.name,
        fileType: file.type,
        fileSize: file.size,
      });

      if (!file.type.startsWith('image/')) {
        throw new Error('Please select a valid image file (JPG, PNG, etc.)');
      }

      if (file.size > 10 * 1024 * 1024) {
        throw new Error('Image file is too large. Please use an image smaller than 10MB.');
      }

      await this.initializeDecoder();

      return new Promise((resolve, reject) => {
        const img = new Image();
        const imageUrl = URL.createObjectURL(file);

        const timeoutId = window.setTimeout(() => {
          URL.revokeObjectURL(imageUrl);
          reject(new Error('Image loading timed out'));
        }, 15000);

        img.onload = async () => {
          window.clearTimeout(timeoutId);
          URL.revokeObjectURL(imageUrl);

          try {
            this.plugin.logger.debug('Image loaded successfully', {
              width: img.width,
              height: img.height,
            });
            const result = await this.scanImageWithOptimizedMethods(img);
            resolve(result);
          } catch (error) {
            this.plugin.logger.error('Error during image scanning:', error);
            reject(error instanceof Error ? error : new Error('Image scanning failed'));
          }
        };

        img.onerror = () => {
          window.clearTimeout(timeoutId);
          URL.revokeObjectURL(imageUrl);
          reject(new Error('Failed to load image file. Please try a different image format.'));
        };

        img.crossOrigin = 'anonymous';
        img.src = imageUrl;
      });
    } catch (error) {
      this.plugin.logger.error('Image scan setup error:', error);
      throw error;
    }
  }

  private async scanImageWithOptimizedMethods(
    img: HTMLImageElement
  ): Promise<BarcodeResult | null> {
    // Optimized scanning methods
    const methods = [
      // Method 1: Direct image scan (fastest)
      { name: 'Direct image scan', process: () => this.tryDirectImageScan(img) },

      // Method 2: Canvas 1:1 (most accurate for normal images)
      { name: 'Canvas 1:1', process: () => this.tryOptimizedCanvasScan(img, 1, false) },

      // Method 3: Canvas 2x scale (for small barcodes)
      { name: 'Canvas 2x scale', process: () => this.tryOptimizedCanvasScan(img, 2, false) },

      // Method 4: Canvas 0.5x scale (for large images)
      { name: 'Canvas 0.5x scale', process: () => this.tryOptimizedCanvasScan(img, 0.5, false) },

      // Method 5: High contrast processing
      {
        name: 'High contrast',
        process: () => this.tryOptimizedCanvasScan(img, 1, true, { contrast: 2.0 }),
      },

      // Method 6: Brightness adjustment
      {
        name: 'Brightness boost',
        process: () => this.tryOptimizedCanvasScan(img, 1, true, { brightness: 1.3 }),
      },

      // Method 7: Threshold processing
      {
        name: 'Binary threshold',
        process: () => this.tryOptimizedCanvasScan(img, 1, true, { threshold: 128 }),
      },
    ];

    for (const method of methods) {
      try {
        this.plugin.logger.debug('Trying method', { method: method.name });
        const result = await method.process();

        if (result) {
          this.plugin.logger.debug('Barcode found', {
            method: method.name,
            code: result.code,
          });
          return result;
        }
      } catch (error: unknown) {
        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
        this.plugin.logger.debug('Method failed', {
          method: method.name,
          error: errorMessage,
        });
      }
    }

    this.plugin.logger.debug('No barcode found after trying all optimized methods');
    return null;
  }

  private async tryDirectImageScan(img: HTMLImageElement): Promise<BarcodeResult | null> {
    try {
      let result: ZXingResult | null = null;

      // Try different ZXing methods for direct image scanning
      if (this.codeReader && this.codeReader.decodeFromImageElement) {
        result = await this.codeReader.decodeFromImageElement(img);
      } else if (this.codeReader && this.codeReader.decodeFromImage) {
        result = await this.codeReader.decodeFromImage(img);
      } else if (this.codeReader && this.codeReader.decode) {
        result = await this.codeReader.decode(img);
      }

      if (result) {
        return {
          code: result.getText(),
          format: result.getBarcodeFormat().toString(),
        };
      }
    } catch {
      // Direct method failed, this is normal
    }
    return null;
  }

  private async tryOptimizedCanvasScan(
    img: HTMLImageElement,
    scale = 1,
    useProcessing = false,
    options: {
      contrast?: number;
      brightness?: number;
      threshold?: number;
    } = {}
  ): Promise<BarcodeResult | null> {
    // Create optimized canvas with willReadFrequently flag to suppress warnings
    const canvas = activeDocument.createElement('canvas');
    const ctx = canvas.getContext('2d', {
      willReadFrequently: true, // This fixes the Canvas2D warnings
    });

    if (!ctx) {
      throw new Error('Could not create canvas context');
    }

    const width = Math.floor(img.width * scale);
    const height = Math.floor(img.height * scale);

    canvas.width = width;
    canvas.height = height;

    // Configure canvas for optimal barcode scanning
    ctx.imageSmoothingEnabled = scale !== 1;
    ctx.imageSmoothingQuality = 'high';

    // Draw image to canvas
    ctx.drawImage(img, 0, 0, width, height);

    // Apply image processing if requested
    if (useProcessing) {
      this.applyOptimizedImageProcessing(ctx, width, height, options);
    }

    try {
      let result: ZXingResult | null = null;

      // Try different ZXing decode methods
      if (this.codeReader && this.codeReader.decodeFromCanvas) {
        result = await this.codeReader.decodeFromCanvas(canvas);
      } else if (this.codeReader && this.codeReader.decode) {
        result = await this.codeReader.decode(canvas);
      } else if (this.codeReader && this.codeReader.decodeFromImageData) {
        const imageData = ctx.getImageData(0, 0, width, height);
        result = await this.codeReader.decodeFromImageData(imageData);
      }

      if (result) {
        return {
          code: result.getText(),
          format: result.getBarcodeFormat().toString(),
        };
      }
    } catch {
      // This method didn't work
    }

    return null;
  }

  private applyOptimizedImageProcessing(
    ctx: CanvasRenderingContext2D,
    width: number,
    height: number,
    options: {
      contrast?: number;
      brightness?: number;
      threshold?: number;
    }
  ): void {
    const imageData = ctx.getImageData(0, 0, width, height);
    const data = imageData.data;

    for (let i = 0; i < data.length; i += 4) {
      let r = data[i];
      let g = data[i + 1];
      let b = data[i + 2];

      // Apply brightness
      if (options.brightness && options.brightness !== 1) {
        r = Math.min(255, r * options.brightness);
        g = Math.min(255, g * options.brightness);
        b = Math.min(255, b * options.brightness);
      }

      // Apply contrast
      if (options.contrast && options.contrast !== 1) {
        r = Math.min(255, Math.max(0, (r - 128) * options.contrast + 128));
        g = Math.min(255, Math.max(0, (g - 128) * options.contrast + 128));
        b = Math.min(255, Math.max(0, (b - 128) * options.contrast + 128));
      }

      // Apply threshold (convert to binary)
      if (options.threshold !== undefined) {
        const gray = 0.299 * r + 0.587 * g + 0.114 * b;
        const thresholded = gray > options.threshold ? 255 : 0;
        r = g = b = thresholded;
      }

      data[i] = r;
      data[i + 1] = g;
      data[i + 2] = b;
      // Alpha channel stays the same
    }

    ctx.putImageData(imageData, 0, 0);
  }

  onunload(): void {
    this.stopScanning();
    super.onunload();
  }
}

export class BarcodeScannerModal extends Modal {
  private component: Component;
  private scanner: BarcodeScanner;
  private videoContainer: HTMLElement;
  private controlsContainer: HTMLElement;
  private statusElement: HTMLElement;
  private isScanning = false;
  private cameraButton: HTMLButtonElement;
  private uploadButton: HTMLButtonElement;
  private uploadInput: HTMLInputElement;

  constructor(
    app: App,
    private plugin: MacrosPlugin,
    private onBarcodeScanned: (barcode: string) => void
  ) {
    super(app);
    this.component = new Component();
  }

  onOpen(): void {
    const { contentEl } = this;
    contentEl.addClass('barcode-scanner-modal');

    contentEl.createEl('h2', {
      text: 'Scan barcode',
      cls: 'barcode-scanner-header',
    });

    if (MobilePermissionHandler.shouldShowPermissionInstructions()) {
      const instructionsEl = contentEl.createDiv({
        cls: 'permission-instructions',
      });
      instructionsEl.createEl('p', {
        text: '­ƒô▒ Camera permission may be required.',
        cls: 'mobile-instruction',
      });
      instructionsEl.createEl('small', {
        text: MobilePermissionHandler.getPermissionInstructions(),
        cls: 'permission-help',
      });
    }

    this.statusElement = contentEl.createDiv({
      cls: 'barcode-scanner-status',
      text: 'Choose a scanning method below',
    });

    this.videoContainer = contentEl.createDiv({
      cls: 'barcode-scanner-video-container',
    });

    this.controlsContainer = contentEl.createDiv({
      cls: 'barcode-scanner-controls',
    });

    void this.createControlsWithDiagnostics();
    void this.initializeScanner();
  }

  private async createControlsWithDiagnostics(): Promise<void> {
    // Run camera diagnostics first
    const diagnostics = await CameraDiagnostics.checkCameraAvailability();

    if (!diagnostics.hasCamera) {
      // Show error message if no camera detected
      const errorDiv = this.controlsContainer.createDiv({
        cls: 'camera-error-message',
      });
      errorDiv.createEl('p', {
        text: 'ÔÜá´©Å no camera detected',
        cls: 'error-title',
      });
      errorDiv.createEl('p', {
        text: diagnostics.error || 'No cameras found on this device',
        cls: 'error-description',
      });
    } else {
      this.plugin.logger.debug('Camera diagnostics', {
        count: diagnostics.cameras.length,
        cameras: diagnostics.cameras,
      });

      // Test basic camera access
      const accessTest = await CameraDiagnostics.testBasicCameraAccess();

      if (!accessTest.success) {
        const warningDiv = this.controlsContainer.createDiv({
          cls: 'camera-warning-message',
        });
        warningDiv.createEl('p', {
          text: 'ÔÜá´©Å camera access issue detected',
          cls: 'warning-title',
        });
        warningDiv.createEl('p', {
          text: accessTest.error || 'Camera permission or access issue',
          cls: 'warning-description',
        });

        // Add troubleshooting info
        const troubleshootDiv = warningDiv.createDiv({ cls: 'troubleshooting' });
        troubleshootDiv.createEl('p', { text: 'Troubleshooting steps:' });
        const list = troubleshootDiv.createEl('ul');
        list.createEl('li', { text: 'Check Windows privacy settings (camera permissions)' });
        list.createEl('li', { text: 'Restart Obsidian' });
        list.createEl('li', { text: 'Try using "upload image" instead' });
        list.createEl('li', { text: 'Check if other apps can access your camera' });
      }
    }

    // Create the camera button
    this.cameraButton = this.controlsContainer.createEl('button', {
      text: diagnostics.hasCamera ? '­ƒôÀ Start camera scan' : '­ƒôÀ Camera Not Available',
      cls: 'mod-cta barcode-scan-camera-btn',
    });

    // Disable camera button if no camera detected
    if (!diagnostics.hasCamera) {
      this.cameraButton.disabled = true;
      this.cameraButton.title = 'No camera detected on this device';
    }

    this.component.registerDomEvent(this.cameraButton, 'click', async () => {
      if (this.isScanning) {
        this.stopCameraScanning();
      } else {
        await this.startCameraScanning();
      }
    });

    // Create other controls
    this.createOtherControls();
  }

  private createOtherControls(): void {
    this.uploadButton = this.controlsContainer.createEl('button', {
      text: '­ƒû╝´©Å upload image',
      cls: 'barcode-scan-upload-btn',
    });

    this.uploadInput = activeDocument.createElement('input');
    this.uploadInput.type = 'file';
    this.uploadInput.accept = 'image/*';
    this.uploadInput.capture = 'environment';
    this.uploadInput.addClass('macros-u-hidden');

    this.component.registerDomEvent(this.uploadButton, 'click', () => {
      this.uploadInput.click();
    });

    this.component.registerDomEvent(this.uploadInput, 'change', async () => {
      const file = this.uploadInput.files?.[0];
      if (file) {
        await this.handleImageUpload(file);
      }
    });

    const manualBtn = this.controlsContainer.createEl('button', {
      text: 'Ô£Å´©Å enter manually',
      cls: 'barcode-scan-manual-btn',
    });

    this.component.registerDomEvent(manualBtn, 'click', () => {
      this.showManualEntry();
    });

    const closeBtn = this.controlsContainer.createEl('button', {
      text: 'Cancel',
      cls: 'barcode-scan-close-btn',
    });

    this.component.registerDomEvent(closeBtn, 'click', () => {
      this.close();
    });
  }

  private async initializeScanner(): Promise<void> {
    this.scanner = new BarcodeScanner(
      this.app,
      this.plugin,
      (result) => this.handleBarcodeDetected(result),
      (error) => this.handleScanError(error)
    );
  }

  private async startCameraScanning(): Promise<void> {
    if (this.isScanning) return;

    try {
      this.statusElement.textContent = 'Requesting camera access...';
      this.cameraButton.textContent = 'ÔÅ│ Initializing...';
      this.cameraButton.disabled = true;

      const cameraReady = await this.scanner.initializeCamera();

      if (!cameraReady) {
        this.cameraButton.textContent = '­ƒôÀ Start camera scan';
        this.cameraButton.disabled = false;
        return;
      }

      this.videoContainer.empty();

      const video = this.videoContainer.createEl('video', {
        cls: 'barcode-scanner-video',
        attr: {
          autoplay: 'true',
          muted: 'true',
          playsinline: 'true',
        },
      });

      this.statusElement.textContent = 'Point camera at barcode... Hold steady for best results.';

      await this.scanner.startScanning(video);
      this.isScanning = true;

      this.updateControlButtons(true);
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : 'Unknown error';
      this.handleScanError(`Camera scanning failed: ${errorMessage}`);
      this.cameraButton.textContent = '­ƒôÀ Start camera scan';
      this.cameraButton.disabled = false;
    }
  }

  private stopCameraScanning(): void {
    if (!this.isScanning) return;

    this.scanner.stopScanning();
    this.isScanning = false;
    this.videoContainer.empty();
    this.statusElement.textContent = 'Camera scanning stopped. Choose another method or try again.';
    this.updateControlButtons(false);
  }

  private async handleImageUpload(file: File): Promise<void> {
    try {
      this.statusElement.textContent = `Scanning image: ${file.name}...`;
      this.uploadButton.textContent = 'ÔÅ│ Scanning...';
      this.uploadButton.disabled = true;

      const result = await this.scanner.scanImageFile(file);

      if (result) {
        this.handleBarcodeDetected(result);
      } else {
        this.statusElement.textContent =
          'No barcode found in image. Try a different image or use manual entry.';
      }
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : 'Unknown error occurred';
      this.handleScanError(`Image scan failed: ${errorMessage}`);
    } finally {
      this.uploadButton.textContent = '­ƒû╝´©Å upload image';
      this.uploadButton.disabled = false;
      this.uploadInput.value = '';
    }
  }

  private showManualEntry(): void {
    const modal = new ManualBarcodeEntryModal(this.app, (barcode) => {
      this.onBarcodeScanned(barcode);
      this.close();
    });

    modal.open();
    this.close();
  }

  private handleBarcodeDetected(result: BarcodeResult): void {
    this.plugin.logger.debug('Barcode scanned successfully', result);

    const validation = BarcodeUtils.validateBarcode(result.code);
    const displayCode = BarcodeUtils.formatBarcodeForDisplay(result.code);

    let message = `Barcode detected: ${displayCode}`;
    if (validation.format) {
      message += ` (${validation.format})`;
    }

    new Notice(message);

    this.onBarcodeScanned(result.code);
    this.close();
  }

  private handleScanError(error: string): void {
    this.plugin.logger.error('Barcode scan error:', error);
    this.statusElement.textContent = error;
    this.updateControlButtons(false);
  }

  private updateControlButtons(scanning: boolean): void {
    if (scanning) {
      this.cameraButton.textContent = 'ÔÅ╣´©Å stop scanning';
      this.cameraButton.disabled = false;
      this.uploadButton.disabled = true;
    } else {
      this.cameraButton.textContent = '­ƒôÀ Start camera scan';
      this.cameraButton.disabled = false;
      this.uploadButton.disabled = false;
    }
  }

  onClose(): void {
    if (this.scanner) {
      this.scanner.stopScanning();
      this.scanner.unload();
    }
    this.component.unload();
    this.contentEl.empty();
  }
}

class ManualBarcodeEntryModal extends Modal {
  private component: Component;
  private barcodeInput: HTMLInputElement;

  constructor(
    app: App,
    private onBarcodeEntered: (barcode: string) => void
  ) {
    super(app);
    this.component = new Component();
  }

  onOpen(): void {
    const { contentEl } = this;
    contentEl.addClass('manual-barcode-entry-modal');

    contentEl.createEl('h2', { text: 'Enter barcode manually' });

    contentEl.createEl('p', {
      // eslint-disable-next-line obsidianmd/ui/sentence-case
      text: 'Enter the numbers from the barcode (EAN/UPC codes are typically 8-13 digits):',
      cls: 'modal-description',
    });

    const inputContainer = contentEl.createDiv({ cls: 'barcode-input-container' });

    this.barcodeInput = inputContainer.createEl('input', {
      type: 'text',
      placeholder: 'e.g., 1234567890123',
      cls: 'barcode-manual-input',
    });

    const buttonContainer = contentEl.createDiv({ cls: 'modal-button-container' });

    const submitBtn = buttonContainer.createEl('button', {
      text: 'Search',
      cls: 'mod-cta',
    });

    const cancelBtn = buttonContainer.createEl('button', {
      text: 'Cancel',
    });

    this.component.registerDomEvent(submitBtn, 'click', () => this.handleSubmit());
    this.component.registerDomEvent(cancelBtn, 'click', () => this.close());
    this.component.registerDomEvent(this.barcodeInput, 'keydown', (e: KeyboardEvent) => {
      if (e.key === 'Enter') {
        this.handleSubmit();
      } else if (e.key === 'Escape') {
        this.close();
      }
    });

    window.setTimeout(() => this.barcodeInput.focus(), 50);
  }

  private handleSubmit(): void {
    const barcode = this.barcodeInput.value.trim();

    if (!barcode) {
      new Notice('Please enter a barcode');
      return;
    }

    const validation = BarcodeUtils.validateBarcode(barcode);

    if (!validation.isValid) {
      new Notice('Please enter a valid barcode (8-14 digits)');
      return;
    }

    if (validation.checksumValid === false) {
      new Notice(`Warning: Barcode has invalid checksum, but searching anyway...`);
    }

    this.onBarcodeEntered(validation.normalizedCode || barcode);
    this.close();
  }

  onClose(): void {
    this.component.unload();
    this.contentEl.empty();
  }
}
